SELECT tbincl.NDA_CNTT_ID , tbincl.DSMS_INTT_ID , tbincl.RCV_INTT_ID , tbincl.DSMS_INTT_NM , tbincl.RCV_INTT_NM
, tbincl.PGRS_STTS_CD , com_cd.COM_CD_NM AS PGRS_STTS_NM
, tbincl.NDA_RQST_TTL , tbincl.RGSN_USER_ID , tbincl.RGSN_TS FROM TB_BOX_IVT_NDA_CNTT_L tbincl LEFT JOIN TB_BOX_IVT_COM_CD_D com_cd ON com_cd.COM_CD_ID = tbincl.PGRS_STTS_CD
WHERE 1=1
AND tbincl.RCV_INTT_ID = #{rcvInttId}
AND tbincl.DSMS_INTT_ID = #{dsmsInttId}
AND tbincl.PGRS_STTS_CD = #{pgrsSttsCd}
ORDER BY tbincl.RGSN_TS DESC

